import React, { useState } from 'react';
import Dashboard from './components/Dashboard';
import AddExpense from './components/AddExpense';
import ExpenseList from './components/ExpenseList';
import './App.css';

function App() {
    const [activePage, setActivePage] = useState('dashboard');
    const [refreshKey, setRefreshKey] = useState(0);

    const handleExpenseAdded = () => {
        setRefreshKey(prev => prev + 1);
        setActivePage('list');
    };

    const renderPage = () => {
        switch (activePage) {
            case 'dashboard':
                return <Dashboard key={refreshKey} />;
            case 'add':
                return <AddExpense onExpenseAdded={handleExpenseAdded} />;
            case 'list':
                return <ExpenseList key={refreshKey} />;
            default:
                return <Dashboard />;
        }
    };

    return (
        <div className="app">
            {/* Sidebar */}
            <aside className="sidebar">
                <div className="logo">
                    <span className="logo-icon">🏗️</span>
                    <div>
                        <h1>ExpenseTrack</h1>
                        <p>Construction & Projects</p>
                    </div>
                </div>

                <nav className="nav-menu">
                    <button
                        className={`nav-item ${activePage === 'dashboard' ? 'active' : ''}`}
                        onClick={() => setActivePage('dashboard')}
                    >
                        <span className="nav-icon">📊</span>
                        Dashboard
                    </button>
                    <button
                        className={`nav-item ${activePage === 'add' ? 'active' : ''}`}
                        onClick={() => setActivePage('add')}
                    >
                        <span className="nav-icon">➕</span>
                        Add Expense
                    </button>
                    <button
                        className={`nav-item ${activePage === 'list' ? 'active' : ''}`}
                        onClick={() => setActivePage('list')}
                    >
                        <span className="nav-icon">📋</span>
                        All Expenses
                    </button>
                </nav>

                <div className="sidebar-footer">
                    <p>© 2024 ExpenseTrack</p>
                </div>
            </aside>

            {/* Main Content */}
            <main className="main-content">
                <header className="top-bar">
                    <div className="top-bar-title">
                        {activePage === 'dashboard' && '📊 Dashboard Overview'}
                        {activePage === 'add' && '➕ Add New Expense'}
                        {activePage === 'list' && '📋 All Expense Records'}
                    </div>
                    <div className="top-bar-info">
                        🔗 Connected to: localhost:8080
                    </div>
                </header>

                <div className="content-area">
                    {renderPage()}
                </div>
            </main>
        </div>
    );
}

export default App;
